generators.filterTemplateSuggestions:
_NuFrRa_filterTemplateSuggestions(r) {
        let t = ".csproj";
        return r.filter(e => typeof e.name == "string" ? e.name.endsWith(t) : !1);
      }

generators.postProcess:
_NuFrRa_postProcess(r) {
    return JSON.parse(r).data.map(e => ({
      name: e.title,
      insertValue: e.id,
      description: e.description
    }));
  }

generators.script:
_NuFrRa_script(r) {
    let t = r.filter(a => !a.startsWith("-")),
        e = t.findIndex(a => a === "package");
    return "curl -s -H \"Accept: application/json\" \"https://api.nuget.org/v3-flatcontainer/".concat(t[e + 1].toLowerCase(), "/index.json\"");
  }

